// Extract research query from the trigger input
const input = $input.first().json;
const query = input.query || '';
const researchType = input.type || 'general';

// Build search URLs based on research type
const urls = [];

if (researchType === 'reviews') {
  urls.push(`https://www.google.com/search?q=${encodeURIComponent(query + ' reviews')}`);
  urls.push(`https://www.google.com/maps/search/${encodeURIComponent(query)}`);
} else if (researchType === 'social') {
  urls.push(`https://www.google.com/search?q=${encodeURIComponent(query + ' site:linkedin.com OR site:instagram.com OR site:facebook.com')}`);
} else if (researchType === 'competitors') {
  urls.push(`https://www.google.com/search?q=${encodeURIComponent(query + ' competitors alternatives')}`);
} else if (researchType === 'industry') {
  urls.push(`https://www.google.com/search?q=${encodeURIComponent(query + ' industry trends 2026')}`);
} else {
  urls.push(`https://www.google.com/search?q=${encodeURIComponent(query)}`);
}

return urls.map(url => ({ json: { url, query, researchType } }));

const html = $input.first().json.data || $input.first().json.body || '';
const query = $input.first().json.query || '';
const researchType = $input.first().json.researchType || 'general';

// Strip HTML tags, scripts, styles
const text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 10000);

return [{ json: { text, query, researchType } }];
